// Phase 1: Supabase connection foundation
// املأ القيم في ملف .env.local ثم شغّل البرنامج من جديد.
// ملاحظة: هذا الملف لا يغيّر التخزين الحالي بعد؛ هو تجهيز آمن للمرحلة الثانية.
import { createClient } from '@supabase/supabase-js';

const supabaseUrl = process.env.REACT_APP_SUPABASE_URL || '';
const supabaseAnonKey = process.env.REACT_APP_SUPABASE_ANON_KEY || '';

export const isSupabaseConfigured = Boolean(supabaseUrl && supabaseAnonKey);

export const supabase = isSupabaseConfigured
  ? createClient(supabaseUrl, supabaseAnonKey, {
      auth: {
        persistSession: true,
        autoRefreshToken: true,
        detectSessionInUrl: true,
      },
      realtime: {
        params: { eventsPerSecond: 10 },
      },
    })
  : null;

export function getSupabaseStatus() {
  return {
    configured: isSupabaseConfigured,
    message: isSupabaseConfigured
      ? 'Supabase hazır: online veritabanı bağlantısı ayarlanmış.'
      : 'Supabase bilgileri girilmedi: sistem güvenli şekilde localStorage modunda çalışıyor.',
  };
}
